{"contents":""""Central config loading from TOML layers with project/global scope resolution.

Layers (low to high priority):
1. acreta/config/default.toml  (shipped with package)
2. ~/.acreta/config.toml       (user global)
3. <repo>/.acreta/config.toml  (project shared)
4. <repo>/.acreta/config.local.toml  (project personal, gitignored)
5. ACRETA_CONFIG env var path  (explicit override, for CI/tests)

API keys come from environment variables only.
"""

from __future__ import annotations

import os
import tomllib
from dataclasses import dataclass
from functools import lru_cache
from pathlib import Path
from typing import Any

from dotenv import load_dotenv

from acreta.config.project_scope import git_root_for, resolve_data_dirs

PACKAGE_DIR = Path(__file__).parent
DEFAULT_CONFIG_PATH = PACKAGE_DIR / "default.toml"
USER_CONFIG_PATH = Path.home() / ".acreta" / "config.toml"
GLOBAL_DATA_DIR = Path.home() / ".acreta"

_LAST_CONFIG_SOURCES: list[dict[str, str]] = []


def load_toml_file(path: Path | None) -> dict:
    """Load a TOML file into a dict, returning ``{}`` on read/parse errors."""
    if not path or not path.exists():
        return {}
    try:
        with open(path, "rb") as handle:
            data = tomllib.load(handle)
    except Exception:
        return {}
    return data if isinstance(data, dict) else {}


def _deep_merge(base: dict[str, Any], override: dict[str, Any]) -> dict[str, Any]:
    """Recursively merge nested dict values with ``override`` precedence."""
    merged = dict(base)
    for key, value in override.items():
        existing = merged.get(key)
        if isinstance(existing, dict) and isinstance(value, dict):
            merged[key] = _deep_merge(existing, value)
        else:
            merged[key] = value
    return merged


def _expand(value: Any, default: Path) -> Path:
    """Expand ``~`` in path-like values with fallback."""
    if value in (None, ""):
        return default
    try:
        return Path(str(value)).expanduser()
    except (TypeError, OSError, ValueError):
        return default


def get_user_config_path() -> Path:
    """Return the canonical user override config path."""
    return USER_CONFIG_PATH


def ensure_user_config_exists() -> Path:
    """Create user config scaffold on first run outside pytest."""
    path = USER_CONFIG_PATH
    if path.exists() or os.getenv("PYTEST_CURRENT_TEST"):
        return path
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(
        "# Acreta user overrides\n"","totalLinesInFile":335}
